    body = charToRaw("{\"PubTator3\": [{\"_id\": \"33054928|None\", \"id\": \"33054928\", \"infons\": {}, \"passages\": [{\"infons\": {\"journal\": \"NCHS Data Brief. 2020 Sep;(378):1-8.\", \"year\": \"2020\", \"type\": \"title\", \"authors\": \"Terlizzi EP, Villarroel MA\"}, \"offset\": 0, \"text\": \"Symptoms of Generalized Anxiety Disorder Among Adults: United States, 2019.\", \"sentences\": [], \"annotations\": [{\"id\": \"1\", \"infons\": {\"identifier\": \"MESH:C000726808\", \"type\": \"Disease\", \"valid\": true, \"normalized\": [\"C000726808\"], \"database\": \"ncbi_mesh\", \"normalized_id\": \"C000726808\", \"biotype\": \"disease\", \"name\": \"general anxiety disorder\", \"accession\": \"@DISEASE_general_anxiety_disorder\"}, \"text\": \"Generalized Anxiety Disorder\", \"locations\": [{\"offset\": 12, \"length\": 28}]}], \"relations\": []}, {\"infons\": {\"type\": \"abstract\"}, \"offset\": 76, \"text\": \"Generalized anxiety disorder (GAD) is characterized by excessive worry that is difficult to control accompanied by physical symptoms including restlessness, being easily fatigued, difficulty concentrating, irritability, muscle tension, or sleep disturbance (1). The GAD-7 scale is a validated brief selfreport measure to screen for GAD and assess the severity of symptoms (2). Adults with GAD-7 scores of 0-4 are considered to have no or minimal symptoms of GAD, while those with scores of 5-9, 10-14, or 15-21 are considered to have mild, moderate, or severe symptoms, respectively (2). This report examines the percentage of adults aged 18 and over who experienced symptoms of anxiety in the past 2 weeks, by severity of symptoms and select demographic characteristics, using the GAD-7 scale.\", \"sentences\": [], \"annotations\": [{\"id\": \"12\", \"infons\": {\"identifier\": \"MESH:C000726808\", \"type\": \"Disease\", \"valid\": true, \"normalized\": [\"C000726808\"], \"database\": \"ncbi_mesh\", \"normalized_id\": \"C000726808\", \"biotype\": \"disease\", \"name\": \"general anxiety disorder\", \"accession\": \"@DISEASE_general_anxiety_disorder\"}, \"text\": \"Generalized anxiety disorder\", \"locations\": [{\"offset\": 76, \"length\": 28}]}, {\"id\": \"13\", \"infons\": {\"identifier\": \"MESH:C000726808\", \"type\": \"Disease\", \"valid\": true, \"normalized\": [\"C000726808\"], \"database\": \"ncbi_mesh\", \"normalized_id\": \"C000726808\", \"biotype\": \"disease\", \"name\": \"general anxiety disorder\", \"accession\": \"@DISEASE_general_anxiety_disorder\"}, \"text\": \"GAD\", \"locations\": [{\"offset\": 106, \"length\": 3}]}, {\"id\": \"14\", \"infons\": {\"identifier\": \"MESH:D011595\", \"type\": \"Disease\", \"valid\": true, \"normalized\": [\"D011595\"], \"database\": \"ncbi_mesh\", \"normalized_id\": \"D011595\", \"biotype\": \"disease\", \"name\": \"Psychomotor Agitation\", \"accession\": \"@DISEASE_Psychomotor_Agitation\"}, \"text\": \"restlessness\", \"locations\": [{\"offset\": 219, \"length\": 12}]}, {\"id\": \"15\", \"infons\": {\"identifier\": \"MESH:C567712\", \"type\": \"Disease\", \"valid\": true, \"normalized\": [\"C567712\"], \"database\": \"ncbi_mesh\", \"normalized_id\": \"C567712\", \"biotype\": \"disease\", \"name\": \"Retinitis Pigmentosa Concentric\", \"accession\": \"@DISEASE_Retinitis_Pigmentosa_Concentric\"}, \"text\": \"difficulty concentrating\", \"locations\": [{\"offset\": 256, \"length\": 24}]}, {\"id\": \"16\", \"infons\": {\"identifier\": \"MESH:D001523\", \"type\": \"Disease\", \"valid\": true, \"normalized\": [\"D001523\"], \"database\": \"ncbi_mesh\", \"normalized_id\": \"D001523\", \"biotype\": \"disease\", \"name\": \"Mental Disorders\", \"accession\": \"@DISEASE_Mental_Disorders\"}, \"text\": \"irritability\", \"locations\": [{\"offset\": 282, \"length\": 12}]}, {\"id\": \"17\", \"infons\": {\"identifier\": \"MESH:D018781\", \"type\": \"Disease\", \"valid\": true, \"normalized\": [\"D018781\"], \"database\": \"ncbi_mesh\", \"normalized_id\": \"D018781\", \"biotype\": \"disease\